#include <cuda_runtime.h>
#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

__global__ void warmup_kernel(float* data, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n) {
        float val = data[idx];
        // Perform compute-intensive work for warmup
        for(int i = 0; i < 1000; i++) {
            val = val * val + 1.0f;
        }
        data[idx] = val;
    }
}

__global__ void measure_kernel(unsigned long long* start_clock, unsigned long long* end_clock, float* data, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx == 0) {
        *start_clock = clock64();
    }

    __syncthreads();

    if (idx < n) {
        float val = data[idx];
        // Perform compute-intensive work to maintain boost clock
        for(int i = 0; i < 10000; i++) {
            val = fmaf(val, val, 1.0f);  // FMA operation
            val = fmaf(val, 0.5f, val);  // Another FMA operation
        }
        data[idx] = val;
    }

    __syncthreads();

    if (idx == 0) {
        *end_clock = clock64();
    }
}

int main() {
    // Device setup
    int deviceId = 0;
    cudaSetDevice(deviceId);

    // Get device properties for grid/block dimensions
    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, deviceId);
    int numSMs = prop.multiProcessorCount;

    // Allocate memory
    float* d_data;
    unsigned long long* d_start_clock;
    unsigned long long* d_end_clock;

    cudaMalloc(&d_data, sizeof(float) * 1024 * numSMs);
    cudaMalloc(&d_start_clock, sizeof(unsigned long long));
    cudaMalloc(&d_end_clock, sizeof(unsigned long long));

    // Initialize data
    std::vector<float> h_data(1024 * numSMs, 1.0f);
    cudaMemcpy(d_data, h_data.data(), sizeof(float) * 1024 * numSMs, cudaMemcpyHostToDevice);

    // Warmup phase - run for at least 100ms to reach boost clock
    cudaEvent_t warmup_start, warmup_stop;
    cudaEventCreate(&warmup_start);
    cudaEventCreate(&warmup_stop);

    cudaEventRecord(warmup_start);

    dim3 warmup_block(256);
    dim3 warmup_grid(numSMs * 8);

    for(int i = 0; i < 50; i++) {  // Multiple iterations for longer warmup
        warmup_kernel<<<warmup_grid, warmup_block>>>(d_data, 1024 * numSMs);
    }
    cudaDeviceSynchronize();

    cudaEventRecord(warmup_stop);
    cudaEventSynchronize(warmup_stop);

    float warmup_time;
    cudaEventElapsedTime(&warmup_time, warmup_start, warmup_stop);

    // Measurement phase - run multiple times and take median
    const int num_runs = 11;
    std::vector<float> frequencies(num_runs);

    for(int run = 0; run < num_runs; run++) {
        cudaEvent_t start_event, stop_event;
        cudaEventCreate(&start_event);
        cudaEventCreate(&stop_event);

        // Launch measurement kernel
        dim3 block(256);
        dim3 grid(numSMs * 4);  // Moderate grid size

        cudaEventRecord(start_event);
        measure_kernel<<<grid, block>>>(d_start_clock, d_end_clock, d_data, 1024 * numSMs);
        cudaEventRecord(stop_event);

        cudaDeviceSynchronize();

        // Get timing from events
        cudaEventSynchronize(stop_event);
        float elapsed_ms = 0;
        cudaEventElapsedTime(&elapsed_ms, start_event, stop_event);

        // Get clock counts
        unsigned long long start_clk, end_clk;
        cudaMemcpy(&start_clk, d_start_clock, sizeof(unsigned long long), cudaMemcpyDeviceToHost);
        cudaMemcpy(&end_clk, d_end_clock, sizeof(unsigned long long), cudaMemcpyDeviceToHost);

        // Calculate frequency
        unsigned long long clock_delta = end_clk - start_clk;
        float time_seconds = elapsed_ms / 1000.0f;

        // Calculate frequency in MHz
        float freq_mhz = static_cast<float>(clock_delta) / (elapsed_ms * 1000.0f);

        frequencies[run] = freq_mhz;

        cudaEventDestroy(start_event);
        cudaEventDestroy(stop_event);
    }

    // Calculate median frequency
    std::sort(frequencies.begin(), frequencies.end());
    float median_freq = frequencies[num_runs / 2];

    // Cleanup
    cudaFree(d_data);
    cudaFree(d_start_clock);
    cudaFree(d_end_clock);
    cudaEventDestroy(warmup_start);
    cudaEventDestroy(warmup_stop);

    // Output only the measured frequency
    printf("%.2f\n", median_freq);

    return 0;
}

