    if (idx < n) {
        output[idx] = input[idx];
    }
}

int main() {
    const size_t array_size = 64 * 1024 * 1024; // 64M floats = 256MB each
    const size_t data_size_bytes = array_size * sizeof(float);

    float* d_input;
    float* d_output;

    cudaMalloc(&d_input, data_size_bytes);
    cudaMalloc(&d_output, data_size_bytes);

    // Initialize input data
    cudaMemset(d_input, 1, data_size_bytes);

    // Warmup - run kernel 3 times
    dim3 block_size(256);
    dim3 grid_size((array_size + block_size.x - 1) / block_size.x);

    for(int i = 0; i < 3; i++) {
        bandwidth_kernel<<<grid_size, block_size>>>(d_input, d_output, array_size);
    }
    cudaDeviceSynchronize();

    // Timing events
    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);

    const int num_iterations = 10;

    // Record start time
    cudaEventRecord(start_event);

    // Run bandwidth test multiple times
    for(int i = 0; i < num_iterations; i++) {
        bandwidth_kernel<<<grid_size, block_size>>>(d_input, d_output, array_size);
    }

    // Record stop time
    cudaEventRecord(stop_event);
    cudaEventSynchronize(stop_event);

    // Calculate elapsed time
    float elapsed_ms = 0;
    cudaEventElapsedTime(&elapsed_ms, start_event, stop_event);
    float elapsed_seconds = elapsed_ms / 1000.0f;

    // Calculate bandwidth
    // Each iteration reads and writes the full array (2 * data_size_bytes)
    // Total bytes processed = 2 * data_size_bytes * num_iterations
    double total_bytes = 2.0 * data_size_bytes * num_iterations;
    double bandwidth_gbps = total_bytes / (elapsed_seconds * 1e9);

    // Cleanup
    cudaFree(d_input);
    cudaFree(d_output);
    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    printf("%.2f\n", bandwidth_gbps);

    return 0;
}

