#include <cuda_runtime.h>
#include <iostream>
#include <vector>

#define WARMUP_ITERATIONS 10
#define MEASURE_ITERATIONS 100
#define SHARED_MEM_SIZE 4096  // 4KB per block
#define THREADS_PER_BLOCK 256
#define NUM_BLOCKS 32

__global__ void shmem_bandwidth_kernel(unsigned long long* cycles) {
    __shared__ float smem[SHARED_MEM_SIZE / sizeof(float)];

    int tid = threadIdx.x;
    int bid = blockIdx.x;
    int global_tid = bid * blockDim.x + tid;

    unsigned long long start_cycle, end_cycle;

    if (global_tid == 0) {
        start_cycle = clock64();
    }

    // Synchronize all threads before starting timing
    __syncthreads();

    if (start_cycle == 0) {  // Only thread 0 has valid start_cycle
        start_cycle = clock64();
    }

    // Perform multiple read/write operations to saturate shared memory bandwidth
    for (int iter = 0; iter < MEASURE_ITERATIONS; iter++) {
        // Coalesced access pattern - each thread accesses its own element
        float val = smem[tid % (SHARED_MEM_SIZE / sizeof(float))];
        smem[tid % (SHARED_MEM_SIZE / sizeof(float))] = val + 1.0f;

        // Additional accesses to increase utilization
        int idx1 = (tid * 7) % (SHARED_MEM_SIZE / sizeof(float));
        int idx2 = ((tid + 1) * 11) % (SHARED_MEM_SIZE / sizeof(float));
        float temp = smem[idx1];
        smem[idx2] = temp * 2.0f;
        smem[idx1] = smem[idx2] + 1.0f;
    }

    __syncthreads();

    if (global_tid == 0) {
        end_cycle = clock64();
        *cycles = end_cycle - start_cycle;
    }
}

int main() {
    // Warmup phase
    unsigned long long* d_cycles;
    cudaMalloc(&d_cycles, sizeof(unsigned long long));

    for (int i = 0; i < WARMUP_ITERATIONS; i++) {
        shmem_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_cycles);
    }
    cudaDeviceSynchronize();

    // Measurement phase
    shmem_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_cycles);
    cudaDeviceSynchronize();

    unsigned long long cycles;
    cudaMemcpy(&cycles, d_cycles, sizeof(unsigned long long), cudaMemcpyDeviceToHost);

    // Calculate total bytes transferred
    size_t total_threads = NUM_BLOCKS * THREADS_PER_BLOCK;
    size_t bytes_per_thread_per_iter = 4 * sizeof(float); // 4 memory operations per iteration
    size_t total_bytes = total_threads * MEASURE_ITERATIONS * bytes_per_thread_per_iter;

    // Assuming a typical boost clock of 1.5 GHz for calculations
    double boost_clock_ghz = 1.5;
    double time_seconds = static_cast<double>(cycles) / (boost_clock_ghz * 1e9);

    double bandwidth_gbps = total_bytes / (time_seconds * 1e9);

    std::cout << bandwidth_gbps << std::endl;

    cudaFree(d_cycles);
    return 0;
}

