#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <algorithm>
#include <time.h>

#define CACHE_LINE_SIZE 128 // Bytes
#define NODE_SIZE (CACHE_LINE_SIZE / sizeof(int))
#define NUM_CHASES 10000
#define NUM_ITERATIONS 50
#define DRAM_ARRAY_SIZE_MB 64
#define FLUSH_ARRAY_SIZE_MB 32

__global__ void initializeNodes(int* nodes, int num_nodes, unsigned long long seed) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= num_nodes) return;

    // Initialize the first integer of each node (the pointer/index to next node)
    nodes[idx * NODE_SIZE] = (idx + 1) % num_nodes;
}

__global__ void shuffleNodes(int* nodes, int num_nodes, unsigned long long seed) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= num_nodes) return;

    // Simple hash-based pseudo-randomization within a block
    unsigned int rand_state = seed ^ idx;
    for (int i = 0; i < 10; ++i) {  // Multiple swaps for better shuffling
        rand_state ^= rand_state << 13;
        rand_state ^= rand_state >> 17;
        rand_state ^= rand_state << 5;

        int swap_idx = rand_state % num_nodes;
        int temp = nodes[idx * NODE_SIZE];
        nodes[idx * NODE_SIZE] = nodes[swap_idx * NODE_SIZE];
        nodes[swap_idx * NODE_SIZE] = temp;
    }
}

__global__ void flushL2Cache(int* flush_buffer, int buffer_size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= buffer_size) return;

    // Access pattern to flush L2 cache
    flush_buffer[idx] = flush_buffer[idx] + 1;
}

__global__ void measureLatency(int* nodes, int num_nodes, long long* times, int* results, int iteration) {
    int tid = threadIdx.x;
    if (tid != 0) return; // Only thread 0 does the measurement

    int idx = 0; // Start from first node
    volatile int* volatile_nodes = (volatile int*)nodes;

    long long start_time = clock64();

    for (int i = 0; i < NUM_CHASES; i++) {
        idx = volatile_nodes[idx * NODE_SIZE]; // Chase the pointer
        if (idx >= num_nodes) idx = 0; // Bounds check
    }

    long long end_time = clock64();

    times[iteration] = end_time - start_time;
    results[iteration] = idx; // Prevent optimization
}

// Function to get median value
long long getMedian(long long* arr, int n) {
    // Create a copy of the array to sort
    long long* sorted_arr = new long long[n];
    for (int i = 0; i < n; i++) {
        sorted_arr[i] = arr[i];
    }

    // Simple bubble sort for small array
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (sorted_arr[j] > sorted_arr[j + 1]) {
                long long temp = sorted_arr[j];
                sorted_arr[j] = sorted_arr[j + 1];
                sorted_arr[j + 1] = temp;
            }
        }
    }

    long long median = sorted_arr[n / 2];
    delete[] sorted_arr;
    return median;
}

int main() {
    const int num_nodes = (DRAM_ARRAY_SIZE_MB * 1024 * 1024) / CACHE_LINE_SIZE;
    const int flush_buffer_size = (FLUSH_ARRAY_SIZE_MB * 1024 * 1024) / sizeof(int);

    int *d_nodes, *d_flush_buffer;
    long long *d_times, *h_times;
    int *d_results, *h_results;

    // Allocate device memory
    cudaMalloc(&d_nodes, num_nodes * NODE_SIZE * sizeof(int));
    cudaMalloc(&d_flush_buffer, flush_buffer_size * sizeof(int));
    cudaMalloc(&d_times, NUM_ITERATIONS * sizeof(long long));
    cudaMalloc(&d_results, NUM_ITERATIONS * sizeof(int));

    h_times = new long long[NUM_ITERATIONS];
    h_results = new int[NUM_ITERATIONS];

    // Initialize nodes in sequence
    dim3 blockSize(256);
    dim3 gridSize((num_nodes + blockSize.x - 1) / blockSize.x);

    initializeNodes<<<gridSize, blockSize>>>(d_nodes, num_nodes, time(NULL));
    cudaDeviceSynchronize();

    // Shuffle nodes to create random access pattern
    shuffleNodes<<<gridSize, blockSize>>>(d_nodes, num_nodes, time(NULL));
    cudaDeviceSynchronize();

    // Run multiple iterations
    for (int iter = 0; iter < NUM_ITERATIONS; iter++) {
        // Flush L2 cache before each measurement
        dim3 flushGridSize((flush_buffer_size + blockSize.x - 1) / blockSize.x);
        flushL2Cache<<<flushGridSize, blockSize>>>(d_flush_buffer, flush_buffer_size);
        cudaDeviceSynchronize();

        // Measure latency
        measureLatency<<<1, 256>>>(d_nodes, num_nodes, d_times, d_results, iter);
        cudaDeviceSynchronize();
    }

    // Copy results back to host
    cudaMemcpy(h_times, d_times, NUM_ITERATIONS * sizeof(long long), cudaMemcpyDeviceToHost);
    cudaMemcpy(h_results, d_results, NUM_ITERATIONS * sizeof(int), cudaMemcpyDeviceToHost);

    // Calculate median time
    long long median_time = getMedian(h_times, NUM_ITERATIONS);
    double avg_cycles_per_access = (double)median_time / NUM_CHASES;

    printf("%.2f\n", avg_cycles_per_access);

    // Cleanup
    cudaFree(d_nodes);
    cudaFree(d_flush_buffer);
    cudaFree(d_times);
    cudaFree(d_results);
    delete[] h_times;
    delete[] h_results;

    return 0;
}

