            }
        }
    }

    double median = sorted_arr[n / 2];
    delete[] sorted_arr;
    return median;
}

int main() {
    // Define the sizes to test (in KB)
    std::vector<double> sizes_kb = {
        128, 256, 512, 768, 1024, 1536, 2048, 2560, 3072, 3584, 4096, 
        4608, 5120, 5632, 6144, 7168, 8192, 10240, 12288, 16384, 20480, 32768
    };

    std::vector<double> latencies;

    dim3 blockSize(256);

    for (size_t i = 0; i < sizes_kb.size(); i++) {
        double size_kb = sizes_kb[i];
        int size_bytes = (int)(size_kb * 1024);
        int num_nodes = size_bytes / CACHE_LINE_SIZE;

        if (num_nodes <= 0) continue;

        int *d_nodes;
        unsigned long long *d_times, *h_times;
        int *d_results, *h_results;

        // Allocate device memory
        cudaMalloc(&d_nodes, num_nodes * NODE_SIZE * sizeof(int));
        cudaMalloc(&d_times, NUM_ITERATIONS * sizeof(unsigned long long));
        cudaMalloc(&d_results, NUM_ITERATIONS * sizeof(int));

        h_times = new unsigned long long[NUM_ITERATIONS];
        h_results = new int[NUM_ITERATIONS];

        // Initialize nodes in sequence
        dim3 gridSize((num_nodes + blockSize.x - 1) / blockSize.x);
        initializeNodes<<<gridSize, blockSize>>>(d_nodes, num_nodes, i * 1000);
        cudaDeviceSynchronize();

        // Shuffle nodes to create random access pattern
        shuffleNodes<<<gridSize, blockSize>>>(d_nodes, num_nodes, i * 1000);
        cudaDeviceSynchronize();

        // Run multiple iterations
        for (int iter = 0; iter < NUM_ITERATIONS; iter++) {
            // Measure latency
            measureLatency<<<1, 256>>>(d_nodes, num_nodes, d_times, d_results, iter);
            cudaDeviceSynchronize();
        }

        // Copy results back to host
        cudaMemcpy(h_times, d_times, NUM_ITERATIONS * sizeof(unsigned long long), cudaMemcpyDeviceToHost);
        cudaMemcpy(h_results, d_results, NUM_ITERATIONS * sizeof(int), cudaMemcpyDeviceToHost);

        // Calculate median time
        double median_time = getMedian(h_times, NUM_ITERATIONS);
        double avg_cycles_per_access = median_time / NUM_CHASES;

        latencies.push_back(avg_cycles_per_access);

        // Cleanup
        cudaFree(d_nodes);
        cudaFree(d_times);
        cudaFree(d_results);
        delete[] h_times;
        delete[] h_results;
    }

    // Find the cliff point where latency increases significantly
    int cliff_index = -1;
    double max_increase = 0.0;

    for (size_t i = 1; i < latencies.size(); i++) {
        double prev_lat = latencies[i-1];
        double curr_lat = latencies[i];
        double increase = (curr_lat - prev_lat) / prev_lat;

        if (increase > max_increase) {
            max_increase = increase;
        }

        // Look for significant jump (more than 50% increase)
        if (increase > 0.5 && cliff_index == -1) {
            cliff_index = i;
        }
    }

    // If no cliff found with 50% threshold, look for the largest increase
    if (cliff_index == -1 && latencies.size() > 1) {
        cliff_index = 1;
        max_increase = 0.0;
        for (size_t i = 1; i < latencies.size(); i++) {
            double prev_lat = latencies[i-1];
            double curr_lat = latencies[i];
            double increase = (curr_lat - prev_lat) / prev_lat;

            if (increase > max_increase) {
                max_increase = increase;
                cliff_index = i;
            }
        }
    }

    // If still no cliff found, use the last size
    if (cliff_index == -1) {
        cliff_index = latencies.size() - 1;
    }

    // Output the L2 cache size in KB
    printf("%.0f\n", sizes_kb[cliff_index]);

    return 0;
}

