#include <cuda_runtime.h>
#include <stdio.h>
#include <algorithm>

#define WARP_SIZE 32
#define NUM_THREADS_PER_BLOCK 256
#define NUM_WARPS_PER_BLOCK (NUM_THREADS_PER_BLOCK / WARP_SIZE)
#define SHARED_MEM_SIZE 1024
#define NUM_ACCESS_ITERATIONS 100

__global__ void conflict_free_kernel(unsigned long long* result) {
    __shared__ int smem[SHARED_MEM_SIZE];

    unsigned long long start_cycle = clock64();

    int tid = threadIdx.x;
    for (int iter = 0; iter < NUM_ACCESS_ITERATIONS; iter++) {
        // Conflict-free access: each thread accesses its own bank
        smem[tid] = tid + iter;
        __syncthreads();
        volatile int val = smem[tid];
        __syncthreads();
    }

    unsigned long long end_cycle = clock64();
    if (tid == 0) {
        *result = end_cycle - start_cycle;
    }
}

__global__ void conflict_kernel(unsigned long long* result) {
    __shared__ int smem[SHARED_MEM_SIZE];

    unsigned long long start_cycle = clock64();

    int tid = threadIdx.x;
    for (int iter = 0; iter < NUM_ACCESS_ITERATIONS; iter++) {
        // All threads in warp access the same bank (bank 0) - creating conflicts
        // Since SHARED_MEM_SIZE is 1024 and there are 32 banks, each bank handles 32 elements
        // Address (tid * 32) % SHARED_MEM_SIZE maps to bank (tid * 32) % 32 = 0 for all threads in warp
        int addr = (tid * 32) % SHARED_MEM_SIZE;
        smem[addr] = tid + iter;
        __syncthreads();
        volatile int val = smem[addr];
        __syncthreads();
    }

    unsigned long long end_cycle = clock64();
    if (tid == 0) {
        *result = end_cycle - start_cycle;
    }
}

int main() {
    unsigned long long *d_result;
    cudaMalloc(&d_result, sizeof(unsigned long long));

    const int num_iterations = 10;
    unsigned long long conflict_times[num_iterations];
    unsigned long long free_times[num_iterations];

    for (int i = 0; i < num_iterations; i++) {
        // Measure conflict-free time
        conflict_free_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(d_result);
        cudaDeviceSynchronize();
        cudaMemcpy(&free_times[i], d_result, sizeof(unsigned long long), cudaMemcpyDeviceToHost);

        // Measure conflict time
        conflict_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(d_result);
        cudaDeviceSynchronize();
        cudaMemcpy(&conflict_times[i], d_result, sizeof(unsigned long long), cudaMemcpyDeviceToHost);
    }

    cudaFree(d_result);

    // Calculate penalties for each iteration
    double penalties[num_iterations];
    for (int i = 0; i < num_iterations; i++) {
        // Total number of accesses per warp = WARP_SIZE * NUM_ACCESS_ITERATIONS * 2 (read + write)
        double total_accesses = WARP_SIZE * NUM_ACCESS_ITERATIONS * 2;
        penalties[i] = (double)(conflict_times[i] - free_times[i]) / total_accesses;
    }

    // Sort to find median
    std::sort(penalties, penalties + num_iterations);

    // Output median penalty
    printf("%.2f\n", penalties[num_iterations / 2]);

    return 0;
}
